// ========================================
// STRUCTURED OUTPUT PARSER & ROUTER v2
// - Generates unique RFQ IDs
// - Robust JSON parsing with multiple fallbacks
// - Validates and normalizes shipment data
// - Handles pod_hint and delivery_deadline
// - Determines routing action
// - Formats all email content
// - Concatenates multi-shipment data for Google Sheets
// ========================================

const input = $input.first().json;
const aiRaw = input.text || input.output || '';
const emailMeta = $('Process Email').first().json.emailMeta || {};

// ========================================
// RFQ ID GENERATOR — Format: RFQ-YYYYMMDD-XXX
// ========================================

function generateRfqId() {
  const now = new Date();
  const datePart = now.toISOString().split('T')[0].replace(/-/g, '');
  const seed = `${now.getTime()}-${emailMeta.threadId || ''}`;
  let hash = 0;
  for (let i = 0; i < seed.length; i++) {
    const char = seed.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  const absHash = Math.abs(hash);
  const suffix = chars[absHash % 32] + chars[(absHash >> 5) % 32] + chars[(absHash >> 10) % 32];
  return `RFQ-${datePart}-${suffix}`;
}

// ========================================
// CONSTANTS
// ========================================

const VALID_TYPES = ['20FT', '40FT', '40HC', '40HQ', '45FT', '20OT', '40OT'];
const VALID_SERVICE_TYPES = ['port-to-port', 'door-to-port', 'port-to-door', 'door-to-door'];

const PORT_FIELD_INFO = {
  pol:  { label: 'Port of Loading (Origin)',        example: 'SHENZHEN, SHANGHAI, NINGBO' },
  pod:  { label: 'Port of Discharge (Destination)', example: 'JEBEL ALI, JEDDAH, DAMMAM, HAMAD PORT' },
  qty:  { label: 'Number of Containers',            example: '2, 5, 10' },
  type: { label: 'Container Type',                  example: '20FT, 40FT, 40HC, 20OT, 40OT' },
  date: { label: 'Cargo Ready Date',                example: '2026-02-15, 20th February' }
};

const DOOR_FIELD_INFO = {
  pol:              { label: 'Port of Loading (Origin)',          example: 'SHENZHEN, SHANGHAI, NINGBO' },
  pod:              { label: 'Port of Discharge (Destination)',   example: 'JEBEL ALI, JEDDAH, DAMMAM, HAMAD PORT' },
  qty:              { label: 'Number of Containers',              example: '2, 5, 10' },
  type:             { label: 'Container Type',                    example: '20FT, 40FT, 40HC, 20OT, 40OT' },
  date:             { label: 'Cargo Ready Date',                  example: '2026-02-15, 20th February' },
  pickup_address:   { label: 'Pickup Address (Origin)',           example: 'Factory name, street, city, country' },
  delivery_address: { label: 'Delivery Address (Destination)',    example: 'Warehouse name, street, area, city' }
};

// ========================================
// ROBUST JSON PARSER
// ========================================

function parseAIOutput(raw) {
  if (!raw || typeof raw !== 'string') return null;
  let str = raw.trim()
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/gi, '');
  for (const pattern of [/\{[\s\S]*\}/, /\{.*\"shipments\".*\}/s]) {
    const match = str.match(pattern);
    if (match) {
      try {
        const parsed = JSON.parse(match[0]);
        if (parsed && typeof parsed === 'object') return parsed;
      } catch (e) {
        try {
          const fixed = match[0]
            .replace(/,\s*}/g, '}')
            .replace(/,\s*]/g, ']')
            .replace(/'/g, '"')
            .replace(/([{,]\s*)(\w+):/g, '$1"$2":');
          const parsed = JSON.parse(fixed);
          if (parsed && typeof parsed === 'object') return parsed;
        } catch (e2) { continue; }
      }
    }
  }
  return null;
}

// ========================================
// NORMALIZERS
// ========================================

function normalizePort(port) {
  if (!port || typeof port !== 'string') return null;
  const p = port.trim().toUpperCase();
  return (p === '' || p === 'NULL' || p === 'N/A' || p === 'TBD') ? null : p;
}

function normalizeQty(qty) {
  if (qty === null || qty === undefined) return null;
  const n = parseInt(qty, 10);
  return isNaN(n) || n <= 0 ? null : n;
}

function normalizeType(type) {
  if (!type || typeof type !== 'string') return null;
  let t = type.trim().toUpperCase().replace(/[^A-Z0-9]/g, '');
  if (['40FTHC', '40HQ', '40FTHQ'].includes(t)) t = '40HC';
  if (['20FTGP', '20GP'].includes(t)) t = '20FT';
  if (['40FTGP', '40GP'].includes(t)) t = '40FT';
  if (['40FTOP', '40OP', '40OPEN', '40OPENTOP'].includes(t)) t = '40OT';
  if (['20FTOP', '20OP', '20OPEN', '20OPENTOP'].includes(t)) t = '20OT';
  return VALID_TYPES.includes(t) ? t : null;
}

function normalizeDate(date) {
  if (!date || typeof date !== 'string') return null;
  const d = date.trim();
  if (d === '' || d.toLowerCase() === 'null' || d === 'N/A' || d === 'TBD') return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(d)) {
    return parseInt(d.substring(0, 4), 10) >= 2024 ? d : null;
  }
  const parsed = new Date(d);
  return (!isNaN(parsed.getTime()) && parsed.getFullYear() >= 2024)
    ? parsed.toISOString().split('T')[0] : null;
}

function normalizeServiceType(st) {
  if (!st || typeof st !== 'string') return 'port-to-port';
  const t = st.trim().toLowerCase();
  return VALID_SERVICE_TYPES.includes(t) ? t : 'port-to-port';
}

function normalizeAddress(addr) {
  if (!addr || typeof addr !== 'string') return null;
  const a = addr.trim();
  return (a === '' || a.toLowerCase() === 'null' || a === 'N/A' || a === 'TBD') ? null : a;
}

function normalizePodHint(hints) {
  if (!Array.isArray(hints)) return [];
  return hints
    .map(h => typeof h === 'string' ? h.trim().toUpperCase() : null)
    .filter(h => h && h !== 'NULL' && h !== 'N/A');
}

function validateShipment(s, index) {
  return {
    num: index + 1,
    pol: normalizePort(s.pol),
    pod: normalizePort(s.pod),
    pod_hint: normalizePodHint(s.pod_hint),
    qty: normalizeQty(s.qty),
    type: normalizeType(s.type),
    date: normalizeDate(s.date),
    delivery_deadline: normalizeDate(s.delivery_deadline),
    service_type: normalizeServiceType(s.service_type),
    pickup_address: normalizeAddress(s.pickup_address),
    delivery_address: normalizeAddress(s.delivery_address)
  };
}

// ========================================
// SHEETS CONCATENATION
// ========================================

function concatenateShipments(shipments) {
  return {
    pol:              shipments.map(s => s.pol || 'TBD').join('\n'),
    pod:              shipments.map(s => s.pod || (s.pod_hint.length ? s.pod_hint.join('/') : 'TBD')).join('\n'),
    container_type:   shipments.map(s => s.type || 'TBD').join('\n'),
    qty:              shipments.map(s => s.qty || 'TBD').join('\n'),
    ready_date:       shipments.map(s => s.date || 'TBD').join('\n'),
    delivery_deadline:shipments.map(s => s.delivery_deadline || '').filter(Boolean).join('\n') || null,
    service_type:     [...new Set(shipments.map(s => s.service_type))].join('\n'),
    pickup_address:   shipments.map(s => s.pickup_address || '').filter(Boolean).join('\n') || null,
    delivery_address: shipments.map(s => s.delivery_address || '').filter(Boolean).join('\n') || null
  };
}

// ========================================
// ROUTING LOGIC
// ========================================

function getMissingPortFields(shipment) {
  const missing = [];
  if (!shipment.pol)  missing.push('pol');
  // pod missing is OK if pod_hint has options — handled separately
  if (!shipment.pod && shipment.pod_hint.length === 0) missing.push('pod');
  if (!shipment.qty)  missing.push('qty');
  if (!shipment.type) missing.push('type');
  if (!shipment.date) missing.push('date');
  return missing;
}

function getMissingDoorFields(shipment) {
  const missing = getMissingPortFields(shipment);
  const st = shipment.service_type;
  if ((st === 'door-to-port' || st === 'door-to-door') && !shipment.pickup_address) {
    missing.push('pickup_address');
  }
  if ((st === 'port-to-door' || st === 'door-to-door') && !shipment.delivery_address) {
    missing.push('delivery_address');
  }
  return missing;
}

function hasPodHintOnly(shipments) {
  // True if any shipment has pod_hint but no confirmed pod — needs human confirmation
  return shipments.some(s => !s.pod && s.pod_hint.length > 0);
}

function determineAction(shipments) {
  const hasDoor = shipments.some(s => s.service_type !== 'port-to-port');

  if (hasDoor) {
    const addressesMissing = shipments.some(s => {
      const st = s.service_type;
      if ((st === 'door-to-port' || st === 'door-to-door') && !s.pickup_address) return true;
      if ((st === 'port-to-door' || st === 'door-to-door') && !s.delivery_address) return true;
      return false;
    });
    if (addressesMissing) {
      const allMissing = shipments.map(s => getMissingDoorFields(s));
      return allMissing.every(m => m.length === 0) ? 'complete' : 'need_door_data';
    }
  }

  const allMissing = shipments.map(s => getMissingPortFields(s));
  if (allMissing.every(m => m.length === 0) && !hasPodHintOnly(shipments)) return 'complete';
  return 'need_port_data';
}

// ========================================
// EMAIL CONTENT FORMATTERS
// ========================================

function formatShipmentForPricing(s, isMulti, total) {
  const header = isMulti ? `Shipment ${s.num} of ${total}\n` : '';
  const podDisplay = s.pod || (s.pod_hint.length ? `TBD (options: ${s.pod_hint.join(' / ')})` : '???');
  const route = `${s.pol || '???'} > ${podDisplay}`;
  const containers = s.qty && s.type
    ? `${s.qty} x ${s.type}`
    : (s.qty ? `${s.qty} containers (type TBD)` : 'TBD');
  const ready = s.date || 'TBD';
  const deadline = s.delivery_deadline ? `Delivery Deadline: ${s.delivery_deadline}` : '';
  const serviceLabel = s.service_type !== 'port-to-port' ? `Service: ${s.service_type.toUpperCase()}` : '';
  const pickup   = s.pickup_address   ? `Pickup: ${s.pickup_address}`   : '';
  const delivery = s.delivery_address ? `Delivery: ${s.delivery_address}` : '';
  const doorInfo = [serviceLabel, pickup, delivery, deadline].filter(Boolean).join('\n');
  return `${header}Route: ${route}\nContainers: ${containers}\nReady Date: ${ready}${doorInfo ? '\n' + doorInfo : ''}`;
}

function formatCurrentDetails(shipments, isMulti) {
  const lines = [];
  shipments.forEach((s, i) => {
    const prefix = isMulti ? `[Shipment ${i + 1}]\n` : '';
    const clean = (str) => str ? str.replace(/\n+/g, ', ').replace(/,\s*,/g, ',').replace(/\s+/g, ' ').trim() : null;

    const parts = [];
    if (s.pol)  parts.push(`Origin Port: ${s.pol}`);
    if (s.pod)  parts.push(`Destination Port: ${s.pod}`);
    if (!s.pod && s.pod_hint.length > 0) parts.push(`POD Options: ${s.pod_hint.join(' or ')} (pending confirmation)`);
    if (s.qty && s.type) parts.push(`Containers: ${s.qty} x ${s.type}`);
    else if (s.qty) parts.push(`Quantity: ${s.qty} containers`);
    if (s.date) parts.push(`Cargo Ready: ${s.date}`);
    if (s.delivery_deadline) parts.push(`Delivery Deadline: ${s.delivery_deadline}`);
    if (s.service_type !== 'port-to-port') parts.push(`Service: ${s.service_type}`);

    const summary = prefix + parts.join(' | ');
    const pickup   = s.pickup_address   ? `Pickup:   ${clean(s.pickup_address)}`   : null;
    const delivery = s.delivery_address ? `Delivery: ${clean(s.delivery_address)}` : null;

    const block = [summary, pickup, delivery].filter(Boolean).join('\n');
    if (block) lines.push(block);
  });
  return lines.length > 0 ? lines.join('\n\n') : 'No shipment details could be extracted';
}

function formatMissingFields(shipments, hasDoor) {
  const allMissing = new Set();
  shipments.forEach(s => {
    const missing = hasDoor ? getMissingDoorFields(s) : getMissingPortFields(s);
    missing.forEach(f => allMissing.add(f));
    // If pod_hint exists but no pod confirmed, add pod as missing
    if (!s.pod && s.pod_hint.length > 0) allMissing.add('pod');
  });
  const fieldInfo = hasDoor ? DOOR_FIELD_INFO : PORT_FIELD_INFO;
  return Array.from(allMissing).map(f => {
    const info = fieldInfo[f];
    if (!info) return null;
    // If pod has hints, give a more helpful prompt
    const podHints = shipments.flatMap(s => s.pod_hint);
    if (f === 'pod' && podHints.length > 0) {
      return `- ${info.label} (Please confirm: ${podHints.join(' or ')}?)`;
    }
    return `- ${info.label} (Example: ${info.example})`;
  }).filter(Boolean).join('\n');
}

function buildSubjectLine(shipments, isMulti, count, action) {
  const s = shipments[0];
  const podDisplay = s.pod || (s.pod_hint.length ? s.pod_hint[0] + '?' : 'TBD');
  const route = `${s.pol || 'TBD'} > ${podDisplay}`;
  const containers = s.qty && s.type ? `${s.qty}x${s.type}` : 'TBD';
  const multiSuffix = isMulti ? ` +${count - 1} more` : '';
  const doorSuffix = s.service_type !== 'port-to-port' ? ` [${s.service_type.toUpperCase()}]` : '';
  let prefix = 'Quote Request';
  if (action === 'need_port_data') prefix = 'Quote (Info Required)';
  if (action === 'need_door_data') prefix = 'Quote (Door - Info Required)';
  return `${prefix}: ${route} [${containers}]${multiSuffix}${doorSuffix}`;
}

// ========================================
// MAIN
// ========================================

const rfqId = generateRfqId();

try {
  const parsed = parseAIOutput(aiRaw);
  if (!parsed || !Array.isArray(parsed.shipments) || parsed.shipments.length === 0) {
    throw new Error('Invalid AI response structure');
  }

  const shipments = parsed.shipments.map((s, i) => validateShipment(s, i));
  const isMulti = parsed.multi === true || shipments.length > 1;
  const count = shipments.length;
  const action = determineAction(shipments);
  const hasDoor = shipments.some(s => s.service_type !== 'port-to-port');
  const sheetsData = concatenateShipments(shipments);

  return [{ json: {
    action,
    rfqId,
    shipments,
    hasDoorService: hasDoor,
    subjectLine: buildSubjectLine(shipments, isMulti, count, action),
    pricingContent: shipments.map(s => formatShipmentForPricing(s, isMulti, count)).join('\n\n'),
    currentDetails: formatCurrentDetails(shipments, isMulti),
    missingFormatted: formatMissingFields(shipments, hasDoor),
    sheetsPol:              sheetsData.pol,
    sheetsPod:              sheetsData.pod,
    sheetsContainerType:    sheetsData.container_type,
    sheetsQty:              sheetsData.qty,
    sheetsReadyDate:        sheetsData.ready_date,
    sheetsDeliveryDeadline: sheetsData.delivery_deadline,
    sheetsServiceType:      sheetsData.service_type,
    sheetsPickupAddress:    sheetsData.pickup_address,
    sheetsDeliveryAddress:  sheetsData.delivery_address
  }}];

} catch (err) {
  return [{ json: {
    action: 'fallback',
    rfqId,
    shipments: [],
    hasDoorService: false,
    subjectLine: `Quote Request: ${emailMeta.subject || 'New Inquiry'}`,
    pricingContent: 'Unable to parse shipment details from email.',
    currentDetails: 'We could not extract shipment details from your email.',
    missingFormatted: Object.entries(PORT_FIELD_INFO).map(([k, v]) => `- ${v.label} (Example: ${v.example})`).join('\n'),
    sheetsPol: 'TBD',
    sheetsPod: 'TBD',
    sheetsContainerType: 'TBD',
    sheetsQty: 'TBD',
    sheetsReadyDate: 'TBD',
    sheetsDeliveryDeadline: null,
    sheetsServiceType: 'port-to-port',
    sheetsPickupAddress: null,
    sheetsDeliveryAddress: null
  }}];
}

