// ========================================
// EMAIL & ATTACHMENT PROCESSOR
// Extracts email content and attachment text
// Passes through all email metadata for threading
// Note: require('xlsx') and require('mammoth') may not be
// available in all n8n environments. They are wrapped in
// try-catch so missing modules are handled gracefully.
// ========================================

const item = $input.first();
const email = item.json;
const binary = item.binary || {};
const keys = Object.keys(binary);

// Core email metadata - passed through entire workflow
const emailMeta = {
  id: email.id || '',
  threadId: email.threadId || '',
  messageId: email.messageId || '',
  subject: email.subject || '',
  from: email.from?.text || email.from || '',
  to: email.to?.text || email.to || '',
  date: email.date || new Date().toISOString(),
  inReplyTo: email.inReplyTo || ''
};

const emailBody = email.text || email.textPlain || email.snippet || '';

// Quick exit if no attachments
if (!keys.length) {
  return [{
    json: {
      emailMeta,
      emailBody,
      attachmentText: '',
      hasAttachments: false,
      attachmentCount: 0
    }
  }];
}

const getExt = (name) => {
  if (!name) return '';
  const i = name.lastIndexOf('.');
  return i > 0 ? name.slice(i).toLowerCase() : '';
};

const processAttachment = async (key) => {
  const att = binary[key];
  const name = att.fileName || key;
  const mime = att.mimeType || '';
  const ext = getExt(name);

  if (att.data === 'filesystem-v2' || mime.includes('image')) return '';

  let buffer;
  try { buffer = Buffer.from(att.data, 'base64'); } catch { return ''; }

  // PDF
  if (ext === '.pdf' || mime.includes('pdf')) {
    try {
      const pdf = require('pdf-parse');
      const data = await pdf(buffer);
      return `[${name}]\n${data.text}`;
    } catch { return ''; }
  }

  // Excel
  if (['.xlsx', '.xls', '.xlsm'].includes(ext) || mime.includes('spreadsheet') || mime.includes('excel')) {
    try {
      const XLSX = require('xlsx');
      const wb = XLSX.read(buffer, { type: 'buffer' });
      let text = `[${name}]\n`;
      wb.SheetNames.forEach(sheet => {
        const rows = XLSX.utils.sheet_to_json(wb.Sheets[sheet], { header: 1, defval: '' });
        text += rows.map(r => r.join(' | ')).join('\n') + '\n';
      });
      return text.trim();
    } catch { return ''; }
  }

  // Word
  if (['.docx', '.doc'].includes(ext) || mime.includes('word')) {
    try {
      const mammoth = require('mammoth');
      const result = await mammoth.extractRawText({ buffer });
      return `[${name}]\n${result.value}`;
    } catch { return ''; }
  }

  // CSV/Text
  if (['.csv', '.txt', '.tsv'].includes(ext) || mime.includes('text/plain') || mime.includes('csv')) {
    try { return `[${name}]\n${buffer.toString('utf8')}`; } catch { return ''; }
  }

  return '';
};

const results = await Promise.all(keys.map(processAttachment));
const rawAttachmentText = results.filter(Boolean).join('\n\n');

// Cap attachment text at 12,000 characters to prevent Gemini token overflow
const attachmentText = rawAttachmentText.substring(0, 12000);

return [{
  json: {
    emailMeta,
    emailBody,
    attachmentText,
    hasAttachments: true,
    attachmentCount: keys.length
  }
}];

// CHINA BUSINESS HOURS CHECK - Battle-Tested
// Added: try-catch, array return format

try {
  const china = DateTime.now().setZone('Asia/Shanghai');
  const hour = china.hour;
  const weekday = china.weekday; // 1=Mon...7=Sun

  // Business hours: Mon-Fri, 9:00 AM - 5:00 PM CST
  const isOpen = weekday <= 5 && hour >= 9 && hour < 17;

  // Calculate next 9:00 AM China time for Wait node
  let resumeDate = china.set({ hour: 9, minute: 0, second: 0, millisecond: 0 });

  if (hour >= 17) {
    resumeDate = resumeDate.plus({ days: 1 });
  } else if (hour >= 9) {
    resumeDate = resumeDate.plus({ days: 1 });
  }

  // Skip weekends
  while (resumeDate.weekday > 5) {
    resumeDate = resumeDate.plus({ days: 1 });
  }

  return [{
    json: {
      isOpen,
      resumeTime: resumeDate.toISO(),
      currentChinaTime: china.toFormat('yyyy-MM-dd HH:mm:ss'),
      reason: isOpen ? 'Business Hours (CST)' : 'Outside Business Hours (CST)'
    }
  }];
} catch (e) {
  return [{
    json: {
      isOpen: true,  // Default to open on error
      resumeTime: new Date().toISOString(),
      currentChinaTime: 'Error',
      reason: 'Error checking time: ' + e.message
    }
  }];
}
